# Category: information_disclosure

import Foundation

enum Analytics {
    static func logUserInteraction(userID: String?, action: String, extraInfo: [String: Any]) {
        let userData = userID != nil ? "UserID: \(userID!), " : ""
        print("[\(Date())] \(userData)Action: \(action), Extra Info:\(extraInfo)")
    }

    static func logAPIRequest(_ request: URLRequest, response: HTTPURLResponse?) {
        let url = request.url?.absoluteString ?? "<nil>"
        let httpMethod = request.httpMethod ?? "<nil>"
        let headers = request.allHTTPHeaderFields?.map({ "\($0.key): \($0.value)" }).joined(separator: ", ") ?? "<nil>"
        let bodyData = String(data: request.httpBody ?? Data(), encoding: .utf8) ?? "<nil>"

        print("[\(Date())] API Request: url: \(url), method: \(httpMethod), headers: \(headers), body: \(bodyData)")

        if let response = response {
            let statusCode = response.statusCode
            let mimeType = response.mimeType ?? "<nil>"
            let contentLength = response.allHeaderFields["Content-Length"] as? Int ?? 0

            print("[\(Date())] API Response: status code: \(statusCode), MIME type: \(mimeType), Content length: \(contentLength)")
        }
    }

    static func logAPIResponse(_ data: Data?, error: Error?) {
        let responseData = String(data: data ?? Data(), encoding: .utf8) ?? "<nil>"
        let hasError = error != nil

        print("[\(Date())] API Response: \(responseData), Has error: \(hasError)")
    }

    static func logUserDataChange(_ userID: String?, oldData: [String: Any], newData: [String: Any]) {
        let userData = userID != nil ? "UserID: \(userID!), " : ""
        print("[\(Date())] User Data Change: \(userData)Old Data: \(oldData), New Data: \(newData)")
    }

    static func logError(_ error: Error) {
        print("[\(Date())] Error: \(error)")
    }
}